from datetime import datetime, timezone


def format_iso(aware: datetime) -> str:
    if aware.tzinfo is None or aware.utcoffset() is None:
        raise ValueError("datetime must be timezone-aware with a defined UTC offset")
    result = aware.isoformat()
    # Ensure an explicit offset is present so the instant is preserved.
    if aware.utcoffset() == timezone.utc.utcoffset(None) and (
        result.endswith("+00:00") or result.endswith("-00:00")
    ):
        return result
    if "+" not in result[10:] and "-" not in result[10:] and "Z" not in result:
        # Fallback: append offset explicitly (should not normally happen).
        result = aware.astimezone().isoformat()
    return result
```

