from datetime import datetime


def compare_moments(a, b):
    def instant_key(dt):
        if not isinstance(dt, datetime):
            raise TypeError("compare_moments() arguments must be datetime instances")

        offset = dt.utcoffset() if dt.tzinfo is not None else None
        if offset is None:
            raise ValueError("compare_moments() arguments must be timezone-aware datetimes")

        local_microseconds = (
            (
                ((dt.toordinal() - 1) * 24 + dt.hour) * 60 + dt.minute
            ) * 60 + dt.second
        ) * 1_000_000 + dt.microsecond

        offset_microseconds = (
            (offset.days * 86_400 + offset.seconds) * 1_000_000
            + offset.microseconds
        )

        return local_microseconds - offset_microseconds

    a_key = instant_key(a)
    b_key = instant_key(b)

    if a_key < b_key:
        return -1
    if a_key > b_key:
        return 1
    return 0
