        for fold in (0, 1):
            aware = naive_dt.replace(tzinfo=tz, fold=fold)
            utc_dt = aware.astimezone(timezone.utc)
            round_tripped = utc_dt.astimezone(tz)

            if round_tripped.replace(tzinfo=None) == naive_dt:
                if all(existing != utc_dt for existing in candidates):
                    candidates.append(utc_dt)

        if not candidates:
            raise ValueError("nonexistent local time")

        return min(candidates)

    start_utc = to_earliest_valid_utc(start_naive)
    end_utc = to_earliest_valid_utc(end_naive)

    return (end_utc - start_utc).total_seconds()
