from datetime import datetime, timezone

def to_epoch_millis(aware):
    if not isinstance(aware, datetime):
        raise TypeError("aware must be a datetime")
    if aware.tzinfo is None or aware.utcoffset() is None:
        raise ValueError("aware must be timezone-aware")

    utc = aware.astimezone(timezone.utc)
    round_tripped = utc.astimezone(aware.tzinfo)

    if (
        round_tripped.replace(tzinfo=None) != aware.replace(tzinfo=None)
        or round_tripped.fold != aware.fold
    ):
        raise ValueError("aware represents a nonexistent local time")

    epoch = datetime(1970, 1, 1, tzinfo=timezone.utc)
    delta = utc - epoch
    return (delta.days * 86_400_000) + (delta.seconds * 1_000) + (delta.microseconds // 1_000)
