from datetime import datetime, timezone
from typing import List, Optional, Union

def earliest_event(events: List[Union[datetime, str]]) -> Optional[datetime]:
    """
    Returns the earliest timezone-aware datetime from a list of events.

    If the input list is empty, returns None.
    If the input contains non-datetime items, raises ValueError.
    If the input contains naive datetimes, raises ValueError.
    """
    if not events:
        return None

    def parse_event(event) -> datetime:
        if isinstance(event, str):
            # Attempt to parse string as ISO format datetime
            dt = datetime.fromisoformat(event)
            if dt.tzinfo is None:
                raise ValueError("String parsed event must be timezone-aware")
            return dt
        elif isinstance(event, datetime):
            if event.tzinfo is None:
                raise ValueError("All events must be timezone-aware")
            return event
        else:
            raise ValueError(f"Unsupported event type: {type(event)}")

    earliest = None
    for event in events:
        dt = parse_event(event)
        if earliest is None or dt < earliest:
            earliest = dt

    return earliest
```

