from datetime import datetime, timedelta, timezone
from zoneinfo import ZoneInfo

def elapsed_seconds(start_naive, end_naive, zone):
    if not isinstance(start_naive, datetime) or not isinstance(end_naive, datetime):
        raise TypeError("Arguments must be datetime objects")
    if not start_naive <= end_naive:
        raise ValueError("start must be <= end")

    tz = ZoneInfo(zone)
    start_dt = start_naive.replace(tzinfo=tz)
    end_dt = end_naive.replace(tzinfo=tz)

    # Handle ambiguous times by choosing the earlier occurrence (fold=0)
    if start_naive.utcoffset() != start_dt.utcoffset():
        start_dt = start_naive.replace(tzinfo=tz, fold=0)
    if end_naive.utcoffset() != end_dt.utcoffset():
        end_dt = end_naive.replace(tzinfo=tz, fold=0)

    return (end_dt - start_dt).total_seconds()
