from datetime import datetime, timedelta, timezone
import zoneinfo

def elapsed_seconds(start_naive, end_naive, zone):
    if start_naive > end_naive:
        raise ValueError("start must be <= end")

    tz = zoneinfo.ZoneInfo(zone)

    def resolve_ambiguous(dt_naive):
        candidates = tz.localize(dt_naive, is_dst=None)
        if len(candidates) == 0:
            raise ValueError(f"No local time for {dt_naive} in {zone}")
        elif len(candidates) == 2:
            return min(candidates)
        else:
            return candidates[0]

    start_dt = resolve_ambiguous(start_naive)
    end_dt = resolve_ambiguous(end_naive)

    diff = end_dt - start_dt
    return float(diff.total_seconds())
